   318|export async function updateRequestStatus(
   319|  requestId: string,
   320|  status: EquipmentRequest['status'],
   321|  currentUid: string
   322|): Promise<void> {
   323|  const db = getFirebaseDb();
   324|  console.log('[Firestore] Updating request status:', requestId, '->', status);
   325|
   326|  const snap = await getDoc(doc(db, 'equipmentRequests', requestId));
   327|  if (!snap.exists()) throw new Error('Request not found');
   328|
   329|  const request = snap.data();
   330|  const isProvider = request.providerUid === currentUid;
   331|  const isCustomer = request.customerUid === currentUid;
   332|
   333|  const validTransitions: Record<string, { allowed: string[]; who: 'provider' | 'customer' | 'both' }> = {
   334|    pending: { allowed: ['accepted', 'rejected', 'cancelled'], who: 'both' },
   335|    accepted: { allowed: ['in_progress', 'cancelled'], who: 'both' },
   336|    in_progress: { allowed: ['completed'], who: 'provider' },
   337|  };
   338|
   339|  const current = request.status as string;
   340|  const rule = validTransitions[current];
   341|
   342|  if (!rule || !rule.allowed.includes(status)) {
   343|    throw new Error(`Invalid status transition: ${current} -> ${status}`);
   344|  }
   345|
   346|  if (rule.who === 'provider' && !isProvider) {
   347|    throw new Error('Only the provider can perform this action');
   348|  }
   349|
   350|  if (status === 'cancelled' && !isCustomer && !isProvider) {
   351|    throw new Error('Only participants can cancel');
   352|  }
   353|
   354|  const updates: Record<string, unknown> = {
   355|    status,
   356|    updatedAt: serverTimestamp(),
   357|  };
   358|
   359|  if (status === 'accepted') {
   360|    updates.allowChat = true;
   361|  }
   362|
   363|  if (status === 'completed' || status === 'rejected' || status === 'cancelled') {
   364|    updates.allowChat = false;
   365|  }
   366|
   367|  await updateDoc(doc(db, 'equipmentRequests', requestId), updates);
   368|  console.log('[Firestore] Request status updated');
